t.script:
//
(function () {

    // ── CSRF ──────────────────────────────────────────────────
    var _csrf = document.querySelector('input[name="csrf_token"]') ?
        document.querySelector('input[name="csrf_token"]').value : '';

    // ── PANEL SWITCHER ────────────────────────────────────────
    var PANELS = { project: 1, team: 2, docs: 3 };
    var PANEL_IDS = ['project', 'team', 'docs'];

    function switchPanel(name) {
        PANEL_IDS.forEach(function (id) {
            var panel = document.getElementById('panel-' + id);
            var btn = document.querySelector('.pcs-nav-item[data-panel="' + id + '"]');
            var dot = document.querySelector('.pcs-dot[data-panel="' + id + '"]');
            if (id === name) {
                if (panel) { panel.style.display = ''; panel.classList.add('pcs-panel--in'); }
                if (btn) btn.classList.add('pcs-nav-active');
                if (dot) dot.classList.add('pcs-dot-active');
            } else {
                if (panel) { panel.style.display = 'none'; panel.classList.remove('pcs-panel--in'); }
                if (btn) btn.classList.remove('pcs-nav-active');
                if (dot) dot.classList.remove('pcs-dot-active');
            }
        });
        var activeBtn = document.querySelector('.pcs-nav-item[data-panel="' + name + '"]');
        if (activeBtn) {
            var t = activeBtn.getAttribute('data-title') || '';
            var d = activeBtn.getAttribute('data-desc') || '';
            var stepEl = document.getElementById('pcsStep');
            if (stepEl) stepEl.textContent = '0' + PANELS[name];
            var titleEl = document.getElementById('pcsTitle');
            if (titleEl) titleEl.textContent = t;
            var descEl = document.getElementById('pcsDesc');
            if (descEl) descEl.textContent = d;
        }
        document.querySelector('.pcs-scroll').scrollTop = 0;
    }

    document.querySelectorAll('.pcs-nav-item').forEach(function (btn) {
        btn.addEventListener('click', function () {
            switchPanel(this.getAttribute('data-panel'));
        });
    });

    document.querySelectorAll('.pcs-dot').forEach(function (dot) {
        dot.addEventListener('click', function () {
            switchPanel(this.getAttribute('data-panel'));
        });
    });

    // Restore panel from URL param
    var _params = new URLSearchParams(window.location.search);
    if (_params.get('success') === '1') { switchPanel('docs'); }

    // ── SHARED JSON CALL ──────────────────────────────────────
    function jsonCall(url, body) {
        return fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'X-CSRFToken': _csrf },
            body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: body })
        }).then(function (r) { return r.json(); }).then(function (d) { return d.result || d; });
    }

    function showMsg(el, text, type) {
        el.innerHTML = '<div class="pc-alert pc-alert-' + type + '" style="margin:0 0 .5rem">' + text + '</div>';
        el.style.display = '';
        setTimeout(function () { el.style.display = 'none'; }, 3500);
    }

    function escHtml(s) {
        var d = document.createElement('span');
        d.textContent = String(s || '');
        return d.innerHTML;
    }

    // ── CSRF from first hidden input ──────────────────────────
    var csrfInputs = document.querySelectorAll('input[name="csrf_token"]');
    if (csrfInputs.length) _csrf = csrfInputs[0].value;

    // ══════════════════════════════════════════════════════════
    // TEAM PANEL
    // ══════════════════════════════════════════════════════════
    (function () {
        var projectSelect  = document.getElementById('memberProjectSelect');
        var memberPanel    = document.getElementById('memberPanel');
        var memberList     = document.getElementById('memberList');
        var memberEmpty    = document.getElementById('memberEmpty');
        var memberMsg      = document.getElementById('memberMsg');
        var nameInput      = document.getElementById('memberNameInput');
        var emailInput     = document.getElementById('memberEmailInput');
        var roleSelect     = document.getElementById('memberRoleSelect');
        var addMemberBtn   = document.getElementById('addMemberBtn');
        var focalSelect    = document.getElementById('focalSelect');
        var assignFocalBtn = document.getElementById('assignFocalBtn');
        var removeFocalBtn = document.getElementById('removeFocalBtn');
        var focalCurrent   = document.getElementById('focalCurrent');
        var focalMsg       = document.getElementById('focalMsg');
        var currentProjectId = null;

        function loadFocalPersons() {
            jsonCall('/customer_support/admin_dashboard/focal_persons', {}).then(function (res) {
                if (res.error || !res.users) return;
                focalSelect.innerHTML = '<option value="">— Select focal person —</option>';
                res.users.forEach(function (u) {
                    var opt = document.createElement('option');
                    opt.value = u.id;
                    opt.textContent = u.name + (u.email ? ' (' + u.email + ')' : '');
                    focalSelect.appendChild(opt);
                });
            });
        }

        function renderFocalCurrent(m) {
            if (!m) {
                focalCurrent.innerHTML = '<span class="pc-no-focal">No focal person assigned yet.</span>';
                removeFocalBtn.style.display = 'none';
                return;
            }
            focalCurrent.innerHTML =
                '<div class="pc-member-row pc-focal-current">' +
                    '<div class="pc-member-avatar pc-avatar-focal">' + escHtml(m.initials) + '</div>' +
                    '<div class="pc-member-info">' +
                        '<span class="pc-member-name">' + escHtml(m.name) + '</span>' +
                        '<span class="pc-member-email">' + escHtml(m.email || '') + '</span>' +
                    '</div>' +
                    '<span class="pc-member-role-tag pc-role-focal">Focal Person</span>' +
                '</div>';
            removeFocalBtn.style.display = '';
        }

        assignFocalBtn.addEventListener('click', function () {
            if (!currentProjectId) { showMsg(focalMsg, 'Select a project first.', 'danger'); return; }
            var uid = focalSelect.value;
            if (!uid) { showMsg(focalMsg, 'Please select a focal person.', 'danger'); return; }
            jsonCall('/customer_support/admin_dashboard/projects/' + currentProjectId + '/focal/assign', { user_id: parseInt(uid) })
                .then(function (res) {
                    if (res.success) { renderFocalCurrent(res.member); showMsg(focalMsg, 'Focal person assigned.', 'success'); }
                    else { showMsg(focalMsg, res.error || 'Failed to assign.', 'danger'); }
                });
        });

        removeFocalBtn.addEventListener('click', function () {
            if (!currentProjectId) return;
            jsonCall('/customer_support/admin_dashboard/projects/' + currentProjectId + '/focal/remove', {})
                .then(function (res) {
                    if (res.success) { renderFocalCurrent(null); showMsg(focalMsg, 'Focal person removed.', 'success'); }
                    else { showMsg(focalMsg, res.error || 'Failed to remove.', 'danger'); }
                });
        });

        function appendMemberRow(m) {
            memberEmpty.style.display = 'none';
            var row = document.createElement('div');
            row.className = 'pc-member-row';
            row.dataset.memberId = m.id;
            row.innerHTML =
                '<div class="pc-member-avatar">' + escHtml(m.initials) + '</div>' +
                '<div class="pc-member-info">' +
                    '<span class="pc-member-name">' + escHtml(m.name) + '</span>' +
                    '<span class="pc-member-email">' + escHtml(m.email || '') + '</span>' +
                '</div>' +
                '<span class="pc-member-role-tag">' + escHtml(m.role_label) + '</span>' +
                '<button class="pc-member-remove" data-member-id="' + m.id + '" title="Remove member"><i class="bi bi-person-dash"></i></button>';
            row.querySelector('.pc-member-remove').addEventListener('click', function () {
                var mid = this.dataset.memberId;
                jsonCall('/customer_support/admin_dashboard/projects/members/' + mid + '/remove', {})
                    .then(function (res) {
                        if (res.success) {
                            row.remove();
                            if (!memberList.querySelector('.pc-member-row')) memberEmpty.style.display = '';
                            showMsg(memberMsg, 'Member removed.', 'success');
                        } else { showMsg(memberMsg, res.error || 'Error removing member.', 'danger'); }
                    });
            });
            memberList.appendChild(row);
        }

        function loadMembers(projectId) {
            memberList.innerHTML = '<div class="pc-members-loading">Loading…</div>';
            jsonCall('/customer_support/admin_dashboard/projects/' + projectId + '/members', {})
                .then(function (res) {
                    memberList.innerHTML = '';
                    if (res.error) { showMsg(memberMsg, res.error, 'danger'); return; }
                    renderFocalCurrent(res.focal || null);
                    if (res.focal) focalSelect.value = res.focal.user_id || '';
                    var members = res.members || [];
                    memberEmpty.style.display = members.length ? 'none' : '';
                    members.forEach(function (m) { appendMemberRow(m); });
                });
        }

        projectSelect.addEventListener('change', function () {
            currentProjectId = this.value || null;
            if (!currentProjectId) { memberPanel.style.display = 'none'; return; }
            memberPanel.style.display = '';
            memberList.innerHTML = '';
            nameInput.value = ''; emailInput.value = '';
            loadMembers(currentProjectId);
        });

        addMemberBtn.addEventListener('click', function () {
            if (!currentProjectId) { showMsg(memberMsg, 'Please select a project first.', 'danger'); return; }
            var name = nameInput.value.trim();
            if (!name) { showMsg(memberMsg, 'Name is required.', 'danger'); return; }
            jsonCall('/customer_support/admin_dashboard/projects/' + currentProjectId + '/members/add',
                { name: name, email: emailInput.value.trim(), role: roleSelect.value })
                .then(function (res) {
                    if (res.success) { appendMemberRow(res.member); nameInput.value = ''; emailInput.value = ''; showMsg(memberMsg, 'Member added.', 'success'); }
                    else { showMsg(memberMsg, res.error || 'Failed to add member.', 'danger'); }
                });
        });

        loadFocalPersons();
    })();

    // ══════════════════════════════════════════════════════════
    // WARRANTY CALCULATOR
    // ══════════════════════════════════════════════════════════
    (function () {
        var warrantySelect = document.getElementById('warranty_months');
        var endDateInput = document.getElementById('end_date');
        var hint = document.getElementById('warranty_expiry_hint');
        var notice = document.getElementById('warranty_notice');
        var noticeText = document.getElementById('warranty_notice_text');

        function updateWarranty() {
            var months = parseInt(warrantySelect.value);
            var endVal = endDateInput.value;
            if (!months || !endVal) { hint.textContent = ''; notice.style.display = 'none'; return; }
            var base = new Date(endVal);
            base.setMonth(base.getMonth() + months);
            var exp = base.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
            hint.textContent = 'Coverage expires: ' + exp;
            noticeText.textContent = ' — Support agents are responsible for issues until ' + exp + '. Tickets raised after this date may be declined.';
            notice.style.display = 'flex';
        }

        warrantySelect.addEventListener('change', updateWarranty);
        endDateInput.addEventListener('change', updateWarranty);

        var keyInput = document.getElementById('project_key');
        if (keyInput) {
            keyInput.addEventListener('input', function () {
                var pos = this.selectionStart;
                this.value = this.value.toUpperCase().replace(/[^A-Z0-9-]/g, '');
                this.setSelectionRange(pos, pos);
            });
        }
    })();

    // ══════════════════════════════════════════════════════════
    // DOCUMENTS PANEL
    // ══════════════════════════════════════════════════════════
    (function () {
        var docProjectSelect   = document.getElementById('docProjectSelect');
        var docPanel           = document.getElementById('docPanel');
        var docProjectIdHidden = document.getElementById('docProjectIdHidden');
        var docList            = document.getElementById('docList');
        var docEmpty           = document.getElementById('docEmpty');
        var docListMsg         = document.getElementById('docListMsg');
        var docsBadge          = document.getElementById('docsBadge');

        var FILE_ICONS  = { pdf: 'bi-file-earmark-pdf-fill', docx: 'bi-file-earmark-word-fill', xlsx: 'bi-file-earmark-excel-fill', txt: 'bi-file-earmark-text-fill' };
        var FILE_COLORS = { pdf: '#ef4444', docx: '#3b82f6', xlsx: '#16a34a', txt: '#64748b' };
        var STATE_LABELS = { pending: 'Pending', ready: 'Ready', error: 'Error' };

        function loadDocuments(projectId) {
            docList.innerHTML = '<div class="pc-members-loading"><i class="bi bi-hourglass-split me-2"></i>Loading documents…</div>';
            docEmpty.style.display = 'none';
            jsonCall('/customer_support/admin_dashboard/projects/' + projectId + '/documents', {})
                .then(function (res) {
                    docList.innerHTML = '';
                    if (res.error) { showMsg(docListMsg, res.error, 'danger'); return; }
                    var docs = res.documents || [];
                    if (docsBadge) {
                        if (docs.length) { docsBadge.textContent = docs.length; docsBadge.style.display = ''; }
                        else { docsBadge.style.display = 'none'; }
                    }
                    if (!docs.length) { docEmpty.style.display = ''; return; }
                    docs.forEach(function (doc) { appendDocRow(doc); });
                });
        }

        function appendDocRow(doc) {
            docEmpty.style.display = 'none';
            var icon = FILE_ICONS[doc.file_type] || 'bi-file-earmark-fill';
            var color = FILE_COLORS[doc.file_type] || '#64748b';
            var stateLabel = STATE_LABELS[doc.state] || doc.state;
            var stateClass = doc.state === 'ready' ? 'pc-doc-state-ready' : (doc.state === 'error' ? 'pc-doc-state-error' : 'pc-doc-state-pending');
            var row = document.createElement('div');
            row.className = 'pc-doc-row';
            row.dataset.docId = doc.id;
            row.innerHTML =
                '<div class="pc-doc-icon" style="color:' + color + '"><i class="bi ' + icon + '"></i></div>' +
                '<div class="pc-doc-info">' +
                    '<span class="pc-doc-name">' + escHtml(doc.name) + '</span>' +
                    '<span class="pc-doc-meta">' + escHtml(doc.filename) + ' · ' + escHtml(doc.created) + '</span>' +
                '</div>' +
                '<span class="pc-doc-state ' + stateClass + '">' + stateLabel + '</span>' +
                '<button class="pc-doc-delete" data-doc-id="' + doc.id + '" title="Delete document"><i class="bi bi-trash3"></i></button>';
            row.querySelector('.pc-doc-delete').addEventListener('click', function () {
                if (!confirm('Delete "' + doc.name + '"? This cannot be undone.')) return;
                jsonCall('/customer_support/admin_dashboard/documents/' + doc.id + '/delete', {})
                    .then(function (res) {
                        if (res.success) {
                            row.remove();
                            if (!docList.querySelector('.pc-doc-row')) docEmpty.style.display = '';
                            showMsg(docListMsg, 'Document deleted.', 'success');
                            if (docsBadge) {
                                var cnt = docList.querySelectorAll('.pc-doc-row').length;
                                if (cnt) { docsBadge.textContent = cnt; } else { docsBadge.style.display = 'none'; }
                            }
                        } else { showMsg(docListMsg, res.error || 'Failed to delete.', 'danger'); }
                    });
            });
            docList.appendChild(row);
        }

        docProjectSelect.addEventListener('change', function () {
            var pid = this.value;
            docProjectIdHidden.value = pid;
            if (!pid) { docPanel.style.display = 'none'; return; }
            docPanel.style.display = '';
            loadDocuments(pid);
        });
    })();

})();
//
